  ('optician-moex-02219', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於隱形眼鏡含水量敘述，下列何者錯誤？', '["含水量高的隱形眼鏡，較適合乾眼症患者使用", "含水量高，舒適感較佳", "水膠隱形眼鏡的含水量高，透氧度較高", "含水量高，較易有蛋白質沉積物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02220', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡的敘述，下列何者錯誤？', '["傳統軟式隱形眼鏡的材質多為甲基丙烯酸羥乙酯（hydroxyethyl methacrylate, HEMA）聚合物構成的水膠", "甲基丙烯酸羥乙酯聚合物的孔洞大小，大於細菌本身，因此配戴後的清潔與消毒可避免細菌沾黏於孔 洞中，以避免感染", "一般甲基丙烯酸羥乙酯聚合物的透氧度比矽水膠材質的隱形眼鏡高", "軟式隱形眼鏡一般浸泡於生理食鹽水中保存，不可乾燥保存"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02221', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '夜間配戴的隱形眼鏡（overnight contact lens wear）如：角膜塑型片，若依據Harvitt和Bonanno的發現， 配戴時Dk/L至少要達多少才能預防整層角膜發生水腫？', '["24", "87", "125", "大於150"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02222', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式透氣隱形眼鏡（RGP）的應用，下列敘述何者錯誤？', '["因配戴軟式隱形眼鏡而產生巨大乳突結膜炎者，可考慮改換配戴RGP鏡片", "有較低的彈性模數（modulus of elasticity），故可有效的矯正殘餘散光（residual astigmatism）", "在高粉塵環境工作者適合配戴RGP", "具有較高的透氧性，更適合遠視患者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02223', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式隱形眼鏡材質發展的先後順序，下列何者正確？①氟矽丙烯酸酯（fluoro-silicone/acrylate）', '["矽氧烷丙烯酸酯（silicone/acrylate）", "丁基合成橡膠（cellulose acetate butyrate）", "聚甲基丙烯酸甲 酯（polymethylmethacrylate, PMMA）", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02224', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '高含水量（60%）水膠軟式隱形眼鏡所需之中心厚度（central thickness），一般為下列何者？', '["0.02 mm以下的中心厚度", "0.03～0.05 mm的中心厚度", "0.06～0.10 mm的中心厚度", "0.10～0.18 mm的中心厚度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02225', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡材質比較，下列敘述何者錯誤？', '["依據美國食品和藥物管理局（FDA）對軟式隱形眼鏡分類中，第4類比第1類的鏡片更容易在鏡片上 沉積蛋白質", "矽水膠鏡片比水膠鏡片較為疏水", "矽水膠鏡片依賴鏡片中的含水量來滲透氧氣", "大部份的矽水膠鏡片彈性模數比水膠鏡片高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02226', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡材質中的彈性模數之敘述，下列何者錯誤？', '["鏡片彈性模數，與鏡片抗變形的能力有相關", "鏡片彈性模數，與視覺品質有相關", "大部分水膠隱形眼鏡材質的彈性模數會比矽水膠隱形眼鏡材質的彈性模數高", "硬式透氣隱形眼鏡的彈性模數會比水膠隱形眼鏡的彈性模數高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
